record.field:
warehouses = env['stock.warehouse'].search([])
for wh in warehouses:
    location = wh.lot_stock_id
    quants = env['stock.quant'].search([('location_id', 'child_of', location.id)])
    product_map = {}
    for quant in quants:
        product_map[quant.product_id.id] = product_map.get(quant.product_id.id, 0.0) + quant.quantity

    for product in env['product.product'].search([('type', '=', 'product')]):
        minimum = product.product_tmpl_id.minimum_stock_qty or 0.0
        if minimum <= 0:
            continue

        qty = product_map.get(product.id, 0.0)
        alert_type = False
        if qty <= 0:
            alert_type = 'out_of_stock'
        elif qty <= minimum:
            alert_type = 'low_stock'

        if not alert_type:
            continue

        existing = env['repair.stock.alert'].search([
            ('product_id', '=', product.id),
            ('warehouse_id', '=', wh.id),
            ('state', 'in', ('active', 'acknowledged')),
            ('alert_type', '=', alert_type),
        ], limit=1)

        if not existing:
            env['repair.stock.alert'].create({
                'product_id': product.id,
                'warehouse_id': wh.id,
                'branch_id': wh.branch_id.id if wh.branch_id else False,
                'alert_type': alert_type,
                'notes': 'Auto-generated by scheduled stock alert check.',
            })

branches = model.search([('is_active_branch', '=', True), ('branch_type', '!=', 'head_office')])
for branch in branches:
    if branch.last_day_close_date == fields.Date.context_today(model):
        continue

    manager = branch.manager_id
    if not manager:
        continue

    email_to = manager.work_email or (manager.user_id and manager.user_id.email) or False
    if not email_to:
        continue

    env['mail.mail'].create({
        'subject': 'Day Close Reminder - %s' % branch.name,
        'email_to': email_to,
        'body_html': '<p>Please complete day close for <strong>%s</strong> for %s.</p>' % (branch.name, fields.Date.context_today(model)),
    }).send()
